function solve(points: number[][], target: number[]): number {

    // Helper to convert point array [x, y, z] to a unique string key "x,y,z"
    const pointToKey = (p: number[]): string => `${p[0]},${p[1]},${p[2]}`;

    // Helper to check if a point matches the target
    const matchesTarget = (p: number[]): boolean => 
        p[0] === target[0] && p[1] === target[1] && p[2] === target[2];

    // --- Step 0: Check initial points ---
    const initialPointsSet = new Set<string>();
    const initialPointsArray: number[][] = [];

    for (const p of points) {
        const key = pointToKey(p);
        if (!initialPointsSet.has(key)) {
            initialPointsSet.add(key);
            initialPointsArray.push(p);
            if (matchesTarget(p)) {
                return 0;
            }
        }
    }

    // S_available stores all unique points found so far.
    // We store them as arrays for easier calculation, and maintain the Set for quick lookups.
    let S_available: number[][] = initialPointsArray;

    let k = 1;

    // Since coordinates are bounded (0-6), the total number of points is finite (7^3 = 343). 
    // The loop will terminate either by finding the target, exhausting all reachable points, or cycling (which is implicitly handled by checking uniqueness).
    while (true) {
        const generatedInThisStep: number[][] = [];
        const newPointKeys = new Set<string>();

        // Iterate over all pairs from S_available (A and B)
        const N = S_available.length;

        // We iterate over all pairs (i, j) such that i < j to avoid redundant checks (a, b) vs (b, a)
        // and self-pairing (a, a).
        for (let i = 0; i < N; i++) {
