                const c: number[] = [
                    Math.floor((a[0] + b[0]) / 2),
                    Math.floor((a[1] + b[1]) / 2),
                    Math.floor((a[2] + b[2]) / 2)
                ];

                const cKey = pointToKey(c);

                // Only consider points that are genuinely new to the entire set S_available U Gen_k
                if (!initialPointsSet.has(cKey) && !newPointKeys.has(cKey)) {

                    // 1. Check if target is found in this generation
                    if (matchesTarget(c)) {
                        return k;
                    }

                    // 2. Mark as new for this generation step
                    newPointKeys.add(cKey);
                    generatedInThisStep.push(c);
                }
            }
        }

